def main():
    print("🌱 Seeding data from BLS API responses...")

    data = {"last_updated": datetime.now(timezone.utc).isoformat(), "series": {}}

    for raw in RAW_RESPONSES:
        sid = raw["seriesID"]
        if sid not in SERIES:
            continue
        observations = []
        for obs in raw["data"]:
            if not obs["period"].startswith("M") or obs["period"] == "M13":
                continue
            if obs["value"] == "-":
                continue
            month = int(obs["period"][1:])
            date_str = f"{obs['year']}-{month:02d}"
            observations.append({
                "year": obs["year"],
                "period": obs["period"],
                "value": obs["value"],
                "date": date_str,
            })
        observations.sort(key=lambda d: d["date"])
        data["series"][sid] = {
            "name": SERIES[sid]["name"],
            "data": observations,
        }

    # Save data
    DATA_FILE.parent.mkdir(parents=True, exist_ok=True)
    with open(DATA_FILE, "w") as f:
        json.dump(data, f, indent=2)
    print(f"💾 Saved {sum(len(s['data']) for s in data['series'].values())} observations to {DATA_FILE}")

    # Compute YoY and generate HTML
    yoy_data = compute_yoy(data)
    html = generate_html(data, yoy_data)
    with open(HTML_FILE, "w") as f:
        f.write(html)
    print(f"🌐 Generated dashboard: {HTML_FILE}")
    print("✅ Seed complete!")


if __name__ == "__main__":
    main()
